const item = $input.first().json;
const headers = item.headers || {};
const body = item.body || item;

// rotatable; valor real fica só na instância n8n
const G2_TOKEN = '__G2_TOKEN__';
const auth = headers.authorization || headers.Authorization || '';

if (G2_TOKEN && auth !== `Bearer ${G2_TOKEN}`) {
  return [{ json: { ok: false, payload: { error: { message: 'Acesso nao autorizado.', type: 'auth_error' } } } }];
}

const messages = Array.isArray(body.messages) ? body.messages : (Array.isArray(item.messages) ? item.messages : []);
let userMessage = '';
for (let i = messages.length - 1; i >= 0; i--) {
  const m = messages[i];
  if (m && m.role === 'user' && m.content) { userMessage = String(m.content); break; }
}
if (!userMessage && body.prompt) userMessage = String(body.prompt);
if (!userMessage) userMessage = 'Mensagem vazia.';

return [{ json: { ok: true, userMessage } }];

const resp = $input.first().json;
const raw = String((resp && resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content) || resp.content || '');

function sanitizeForG2(text) {
  let out = text;
  out = out.replace(/```[\s\S]*?```/g, ' ');
  out = out.replace(/`([^`]+)`/g, '$1');
  out = out.replace(/\*\*([^*]+)\*\*/g, '$1');
  out = out.replace(/\*([^*]+)\*/g, '$1');
  out = out.replace(/__([^_]+)__/g, '$1');
  out = out.replace(/_([^_]+)_/g, '$1');
  out = out.replace(/^\s*[-*•]\s+/gm, '');
  out = out.replace(/#{1,6}\s*/g, '');
  out = out.replace(/\[([^\]]+)\]\([^)]+\)/g, '$1');
  out = out.replace(/https?:\/\/\S+/g, '[link]');
  out = out.replace(/\s+/g, ' ').trim();
  if (!out) out = 'Não consegui responder agora. Tenta de novo em instantes.';
  if (out.length > 300) out = out.slice(0, 297).trimEnd() + '...';
  return out;
}

const content = sanitizeForG2(raw);
const now = Math.floor(Date.now() / 1000);
return [{ json: { statusCode: 200, payload: {
  id: `chatcmpl-iris-g2-${now}`, object: 'chat.completion', created: now, model: 'iris-g2-bridge',
  choices: [{ index: 0, message: { role: 'assistant', content }, finish_reason: 'stop' }],
  usage: { prompt_tokens: 0, completion_tokens: content.length, total_tokens: content.length }
} } }];

// HTTP falhou/estourou 22s (tool-call longo, credencial ausente, ou Iris offline)
const content = 'Tô resolvendo isso e te aviso depois.';
const now = Math.floor(Date.now() / 1000);
return [{ json: { statusCode: 200, payload: {
  id: `chatcmpl-iris-g2-${now}`, object: 'chat.completion', created: now, model: 'iris-g2-bridge',
  choices: [{ index: 0, message: { role: 'assistant', content }, finish_reason: 'stop' }],
  usage: { prompt_tokens: 0, completion_tokens: content.length, total_tokens: content.length }
} } }];
